D.ATT_COMBO={"secure+secure":{label:"Secure Haven",risk:.05,dynamics:"Mutual safety, strong repair, high resilience."},"secure+anxious":{label:"Calming Anchor",risk:.2,dynamics:"Secure partner soothes anxiety; protest behavior may arise."},"secure+avoidant":{label:"Patient Bridge",risk:.25,dynamics:"Secure partner models closeness; avoidant may withdraw under pressure."},"secure+fearful":{label:"Stabilizing Force",risk:.3,dynamics:"Secure partner provides consistency; fearful may oscillate."},"secure+disorganized":{label:"Grounding Presence",risk:.35,dynamics:"Secure partner absorbs chaos; disorganized needs high patience."},"anxious+anxious":{label:"Intensity Loop",risk:.5,dynamics:"High emotional intensity, mutual reassurance-seeking, escalation risk."},"anxious+avoidant":{label:"Pursuit-Distance Trap",risk:.65,dynamics:"Classic anxious-avoidant trap: one pursues, one retreats."},"anxious+fearful":{label:"Volatile Connection",risk:.6,dynamics:"Intense bond with frequent ruptures and desperate repair."},"anxious+disorganized":{label:"Chaos Spiral",risk:.7,dynamics:"Unpredictable cycles of closeness and crisis."},"avoidant+avoidant":{label:"Parallel Orbits",risk:.45,dynamics:"Comfortable distance but emotional desert; low conflict, low intimacy."},"avoidant+fearful":{label:"Approach-Retreat",risk:.55,dynamics:"Fearful craves what avoidant withholds; painful push-pull."},"avoidant+disorganized":{label:"Disconnected",risk:.6,dynamics:"Both struggle with closeness; emotional isolation likely."},"fearful+fearful":{label:"Mutual Minefield",risk:.7,dynamics:"Both want and fear intimacy; high rupture frequency."},"fearful+disorganized":{label:"Destabilized",risk:.75,dynamics:"Neither can provide safety; professional support essential."},"disorganized+disorganized":{label:"Storm Pattern",risk:.85,dynamics:"Maximum unpredictability; cycle of crisis and repair."},"anxious-secure+avoidant-secure":{label:"Healing Bridge",risk:.2,dynamics:"Both trending secure; growth-oriented with occasional old patterns."},"earned-secure+anxious":{label:"Learned Safety",risk:.25,dynamics:"Earned-secure models regulation; anxious benefits from stability."},"earned-secure+avoidant":{label:"Gradual Opening",risk:.3,dynamics:"Earned-secure demonstrates vulnerability; avoidant may slowly open."},"codependent+anxious":{label:"Enmeshed Bind",risk:.6,dynamics:"Excessive merger; individual identity erodes."},"codependent+avoidant":{label:"Suffocating Gap",risk:.65,dynamics:"Codependent clings, avoidant suffocates; toxic cycle."},"codependent+codependent":{label:"Total Fusion",risk:.7,dynamics:"Complete enmeshment; no individual boundaries."},"codependent+secure":{label:"Boundary Teacher",risk:.35,dynamics:"Secure models healthy separation; codependent learns autonomy."}};
D.getAttCombo=function(a,b){var k1=a+"+"+b,k2=b+"+"+a;if(D.ATT_COMBO[k1])return D.ATT_COMBO[k1];if(D.ATT_COMBO[k2])return D.ATT_COMBO[k2];var bm={"anxious-secure":"secure","avoidant-secure":"secure","anxious-avoidant":"anxious","fearful-anxious":"fearful","fearful-avoidant":"fearful","earned-secure":"secure"};var ba=bm[a]||a,bb=bm[b]||b;k1=ba+"+"+bb;k2=bb+"+"+ba;return D.ATT_COMBO[k1]||D.ATT_COMBO[k2]||{label:"Unique Dynamic",risk:.4,dynamics:"A less-studied pairing; outcomes depend on individual growth."};};
