D.METRIC_CONTEXT={emotionRegulation:[{min:.8,label:"Excellent",desc:"Strong self-regulation under pressure."},{min:.6,label:"Good",desc:"Generally manages emotions well."},{min:.4,label:"Fair",desc:"Sometimes overwhelmed by emotions."},{min:.2,label:"Poor",desc:"Frequently reactive or shut down."},{min:0,label:"Critical",desc:"Unable to manage emotional responses."}],selfWorth:[{min:.8,label:"Confident",desc:"Strong sense of personal value."},{min:.6,label:"Adequate",desc:"Generally positive self-image."},{min:.4,label:"Fragile",desc:"Self-doubt surfaces under stress."},{min:.2,label:"Low",desc:"Persistent negative self-perception."},{min:0,label:"Depleted",desc:"Deeply impaired sense of worth."}],secureWithPartner:[{min:.8,label:"Very Secure",desc:"Feels safe and valued."},{min:.6,label:"Mostly Secure",desc:"Generally feels safe with partner."},{min:.4,label:"Uncertain",desc:"Some anxiety about the relationship."},{min:.2,label:"Insecure",desc:"Frequent worry about partner's availability."},{min:0,label:"Unsafe",desc:"Does not feel safe with partner."}],hope:[{min:.8,label:"Optimistic",desc:"Believes things can and will improve."},{min:.6,label:"Hopeful",desc:"Sees possibility for positive change."},{min:.4,label:"Wavering",desc:"Sometimes doubts things will get better."},{min:.2,label:"Discouraged",desc:"Losing faith in improvement."},{min:0,label:"Hopeless",desc:"Cannot see a path forward."}],rejectionSensitivity:[{min:.8,label:"Extreme",desc:"Devastated by any perceived slight."},{min:.6,label:"High",desc:"Overreacts to criticism or distance."},{min:.4,label:"Moderate",desc:"Sensitive but can recover."},{min:.2,label:"Low",desc:"Handles rejection reasonably well."},{min:0,label:"Resilient",desc:"Rarely affected by perceived rejection."}],trustInPartner:[{min:.8,label:"Deep Trust",desc:"Fully confident in partner."},{min:.6,label:"Solid",desc:"Generally trusts partner's intentions."},{min:.4,label:"Guarded",desc:"Some reservations about reliability."},{min:.2,label:"Suspicious",desc:"Frequently questions partner's motives."},{min:0,label:"Broken",desc:"No confidence in partner."}],externalStress:[{min:.8,label:"Overwhelming",desc:"Life circumstances are crushing."},{min:.6,label:"Heavy",desc:"Significant external pressures."},{min:.4,label:"Moderate",desc:"Normal life stressors."},{min:.2,label:"Light",desc:"Relatively low outside pressure."},{min:0,label:"Minimal",desc:"Life circumstances are stable and supportive."}],selfExpectations:[{min:.8,label:"Perfectionist",desc:"Impossibly high standards."},{min:.6,label:"High",desc:"Strong internal standards."},{min:.4,label:"Balanced",desc:"Reasonable expectations of self."},{min:.2,label:"Relaxed",desc:"Easy-going self-assessment."},{min:0,label:"Disengaged",desc:"Few standards for self."}],health:[{min:.85,label:"Thriving",desc:"Psychologically flourishing."},{min:.7,label:"Healthy",desc:"Good overall wellbeing."},{min:.55,label:"Stable",desc:"Functioning adequately."},{min:.4,label:"Struggling",desc:"Noticeable difficulties."},{min:.25,label:"At Risk",desc:"Significant impairment."},{min:0,label:"In Crisis",desc:"Severe dysfunction."}],safety:[{min:.8,label:"Very Safe",desc:"Both partners feel protected."},{min:.6,label:"Mostly Safe",desc:"Generally secure environment."},{min:.4,label:"Uncertain",desc:"Safety is inconsistent."},{min:.2,label:"Compromised",desc:"Frequent emotional harm."},{min:0,label:"Dangerous",desc:"No emotional safety."}],trust:[{min:.8,label:"Strong",desc:"Deep mutual confidence."},{min:.6,label:"Solid",desc:"Reliable but not unshakable."},{min:.4,label:"Fragile",desc:"Easily disrupted by setbacks."},{min:.2,label:"Damaged",desc:"Significant trust violations."},{min:0,label:"Broken",desc:"No foundation of trust."}],bond:[{min:.8,label:"Deep",desc:"Profound emotional connection."},{min:.6,label:"Strong",desc:"Meaningful attachment."},{min:.4,label:"Moderate",desc:"Some emotional depth."},{min:.2,label:"Weak",desc:"Surface-level connection."},{min:0,label:"Absent",desc:"No emotional bond."}],tension:[{min:.7,label:"Critical",desc:"Explosive potential."},{min:.5,label:"High",desc:"Significant unresolved stress."},{min:.3,label:"Moderate",desc:"Some underlying friction."},{min:.15,label:"Low",desc:"Minor background stress."},{min:0,label:"Calm",desc:"Relaxed relational atmosphere."}],friction:[{min:.7,label:"Severe",desc:"Constant daily irritation."},{min:.5,label:"High",desc:"Frequent annoyances."},{min:.3,label:"Moderate",desc:"Occasional irritants."},{min:.15,label:"Low",desc:"Rarely bothered."},{min:0,label:"Smooth",desc:"Day-to-day harmony."}]};
D.getMetricLabel=function(key,val){var ranges=D.METRIC_CONTEXT[key];if(!ranges){if(val>=.8)return{label:"Very High",desc:""};if(val>=.6)return{label:"High",desc:""};if(val>=.4)return{label:"Moderate",desc:""};if(val>=.2)return{label:"Low",desc:""};return{label:"Very Low",desc:""};}for(var i=0;i<ranges.length;i++){if(val>=ranges[i].min)return ranges[i];}return ranges[ranges.length-1];};
D.BIO={heartRate:{label:"Heart Rate",unit:"bpm",baseline:72,ranges:[{state:"calm",min:60,max:75,label:"Resting"},{state:"elevated",min:76,max:95,label:"Elevated"},{state:"high",min:96,max:120,label:"High"},{state:"acute",min:121,max:160,label:"Acute Stress"}],shortTerm:"Elevated heart rate reduces cognitive clarity and increases emotional reactivity.",longTerm:"Chronic elevation linked to cardiovascular disease, hypertension, and immune suppression.",solutions:"Box breathing (4-4-4-4), progressive muscle relaxation, mindfulness meditation."},breathing:{label:"Breathing Rate",unit:"breaths/min",baseline:15,ranges:[{state:"calm",min:10,max:16,label:"Normal"},{state:"elevated",min:17,max:22,label:"Shallow/Rapid"},{state:"high",min:23,max:30,label:"Hyperventilation Risk"}],shortTerm:"Rapid shallow breathing triggers sympathetic nervous system activation.",longTerm:"Chronic shallow breathing reduces oxygen efficiency and increases anxiety baseline.",solutions:"Diaphragmatic breathing, 4-7-8 technique, vagal toning exercises."},cortisol:{label:"Cortisol Level",unit:"relative",baseline:.4,ranges:[{state:"low",min:0,max:.3,label:"Low"},{state:"normal",min:.31,max:.55,label:"Normal"},{state:"elevated",min:.56,max:.75,label:"Elevated"},{state:"high",min:.76,max:1,label:"Chronically High"}],shortTerm:"Acute cortisol mobilizes energy but impairs memory and empathy.",longTerm:"Chronic high cortisol degrades hippocampus, weakens immunity, disrupts sleep.",solutions:"Regular exercise, adequate sleep, social connection, nature exposure."},muscleTension:{label:"Muscle Tension",unit:"level",baseline:.3,ranges:[{state:"relaxed",min:0,max:.3,label:"Relaxed"},{state:"mild",min:.31,max:.5,label:"Mild Tension"},{state:"moderate",min:.51,max:.7,label:"Moderate"},{state:"severe",min:.71,max:1,label:"Severe/Chronic"}],shortTerm:"Tension headaches, jaw clenching, shoulder pain.",longTerm:"Chronic pain syndromes, TMJ disorders, postural problems.",solutions:"Progressive muscle relaxation, massage, stretching, yoga."},sleepQuality:{label:"Sleep Quality",unit:"estimate",baseline:.65,ranges:[{state:"good",min:.7,max:1,label:"Restorative"},{state:"fair",min:.5,max:.69,label:"Adequate"},{state:"poor",min:.3,max:.49,label:"Disrupted"},{state:"severe",min:0,max:.29,label:"Severely Impaired"}],shortTerm:"Poor sleep increases irritability, reduces empathy and patience.",longTerm:"Chronic sleep disruption linked to depression, immune dysfunction, cognitive decline.",solutions:"Sleep hygiene routine, consistent schedule, limit screens, relaxation before bed."},immuneFunction:{label:"Immune Function",unit:"estimate",baseline:.7,ranges:[{state:"strong",min:.7,max:1,label:"Robust"},{state:"normal",min:.5,max:.69,label:"Normal"},{state:"weakened",min:.3,max:.49,label:"Weakened"},{state:"suppressed",min:0,max:.29,label:"Suppressed"}],shortTerm:"Stress-weakened immunity increases susceptibility to illness.",longTerm:"Chronic suppression linked to autoimmune conditions and frequent infections.",solutions:"Stress management, adequate sleep, nutrition, moderate exercise, social support."}};
