D.IND_REC_RULES=[{condition:function(p){return p.emotionRegulation<.40;},emoji:"\uD83E\uDDD8",text:"Emotion regulation is low. Try mindfulness, journaling, or grounding exercises.",priority:1},{condition:function(p){return p.selfWorth<.40;},emoji:"\uD83D\uDC8E",text:"Self-worth needs attention. Practice self-compassion and challenge negative self-talk.",priority:1},{condition:function(p){return p.hope<.35;},emoji:"\uD83C\uDF1F",text:"Hope is fading. Set one small achievable goal today. Progress rebuilds belief.",priority:1},{condition:function(p){return p.rejectionSensitivity>.65;},emoji:"\uD83D\uDEE1",text:"High rejection sensitivity. Practice pausing before reacting to perceived slights.",priority:2},{condition:function(p){return p.externalStress>.65;},emoji:"\uD83C\uDFD4",text:"External stress is overwhelming. Prioritize one stress reducer: exercise, nature, or rest.",priority:2},{condition:function(p){return p.trustInPartner<.40;},emoji:"\uD83D\uDD12",text:"Low trust in partner. Focus on observing small positive actions before making judgments.",priority:2},{condition:function(p){return p.secureWithPartner<.40;},emoji:"\uD83E\uDDE9",text:"Feeling insecure with partner. Communicate one specific need clearly and kindly.",priority:2},{condition:function(p){return p.wot<.35;},emoji:"\u26A0",text:"Window of Tolerance is narrow. Practice vagal toning: cold water on face, humming, slow exhale.",priority:1},{condition:function(p){return p.selfExpectations>.80;},emoji:"\uD83C\uDFAF",text:"Perfectionism detected. Challenge 'should' statements. Good enough is often excellent.",priority:3},{condition:function(p){return p.health>.80;},emoji:"\u2728",text:"Strong psychological health. Maintain through continued self-awareness and connection.",priority:4},{condition:function(p){var mhCount=0;var mk=Object.keys(p.mh);for(var i=0;i<mk.length;i++){if(p.mh[mk[i]]>=5)mhCount++;}return mhCount>=2;},emoji:"\uD83C\uDFE5",text:"Multiple significant mental health factors active. Professional support strongly recommended.",priority:0}];
