D.REL_REC_RULES=[{condition:function(r,s){return r.trust<.40;},emoji:"\uD83D\uDD12",text:"Trust is low. Prioritize consistency and follow-through on small promises.",priority:1},{condition:function(r,s){return r.safety<.40;},emoji:"\uD83D\uDEE1",text:"Emotional safety is compromised. Avoid criticism and contempt. Focus on validation.",priority:1},{condition:function(r,s){return r.tension>.55;},emoji:"\u26A1",text:"Tension is high. Take a 20-minute break before difficult conversations.",priority:1},{condition:function(r,s){return r.connection<.35;},emoji:"\uD83D\uDD17",text:"Feeling disconnected. Schedule uninterrupted quality time together.",priority:2},{condition:function(r,s){return r.honesty<.40;},emoji:"\uD83D\uDCAC",text:"Honesty is low. Practice sharing one honest feeling per day without blame.",priority:2},{condition:function(r,s){return r.growth<.35;},emoji:"\uD83C\uDF31",text:"Growth has stalled. Try something new together or discuss one future goal.",priority:2},{condition:function(r,s){return r.intimacy<.35;},emoji:"\u2764",text:"Intimacy is fading. Increase physical affection and emotional vulnerability.",priority:2},{condition:function(r,s){return r.friction>.50;},emoji:"\uD83E\uDE78",text:"Daily friction is wearing you down. Address recurring irritants with I-statements.",priority:2},{condition:function(r,s){return s.conflictLvl>=4;},emoji:"\uD83D\uDD25",text:"Conflict level is elevated. Consider a structured conversation with ground rules.",priority:1},{condition:function(r,s){return r.overall>=.70;},emoji:"\u2728",text:"Relationship is in good shape. Keep investing in what's working.",priority:4}];


